 document.addEventListener('DOMContentLoaded',()=>{const header=document.querySelector('header');const hero=document.querySelector('.hero');const mobileNavToggle=document.querySelector('.mobile-nav-toggle');const mobileNavClose=document.querySelector('.mobile-nav-close');const mobileNavContainer=document.querySelector('.mobile-nav-container');const body=document.body;if(!header || !hero){return;}const setHeroPadding=()=>{const headerHeight=header.offsetHeight;hero.style.paddingTop=`${headerHeight-10}px`;};setHeroPadding();window.addEventListener('resize',setHeroPadding);const heroQuoteButton=document.querySelector('.hero-cta.quote-trigger');const heroContactActions=document.querySelector('.hero-contact-actions');if(heroQuoteButton && heroContactActions){heroQuoteButton.addEventListener('click',()=>{heroQuoteButton.classList.add('hide');heroContactActions.classList.add('active');});document.addEventListener('click',(event)=>{const isHeroClick=event.target.closest('.hero-cta-container');if(!isHeroClick && heroContactActions.classList.contains('active')){heroQuoteButton.classList.remove('hide');heroContactActions.classList.remove('active');}});}if(mobileNavToggle && mobileNavContainer){const closeMenu=()=>{mobileNavToggle.classList.remove('active');mobileNavContainer.classList.remove('active');body.classList.remove('no-scroll');body.classList.remove('menu-open');};mobileNavToggle.addEventListener('click',(e)=>{e.stopPropagation();mobileNavToggle.classList.toggle('active');mobileNavContainer.classList.toggle('active');body.classList.toggle('no-scroll');body.classList.toggle('menu-open');});if(mobileNavClose){mobileNavClose.addEventListener('click',closeMenu);}const mobileNavLinks=document.querySelectorAll('.mobile-nav-container .nav-link');mobileNavLinks.forEach(link=>{link.addEventListener('click',closeMenu);});document.addEventListener('click',(event)=>{const isClickInside=mobileNavContainer.contains(event.target)|| mobileNavToggle.contains(event.target)||(mobileNavClose && mobileNavClose.contains(event.target));if(!isClickInside && mobileNavContainer.classList.contains('active')){closeMenu();}});}const tabsContainer=document.querySelector('.service-tabs');if(tabsContainer){const tabButtons=tabsContainer.querySelectorAll('.tab-btn');const tabPanes=document.querySelectorAll('.tab-content .tab-pane');tabsContainer.addEventListener('click',(e)=>{if(!e.target.matches('.tab-btn'))return;const targetTab=e.target.dataset.tab;tabButtons.forEach(btn=> btn.classList.remove('active'));e.target.classList.add('active');tabPanes.forEach(pane=>{if(pane.id===targetTab){pane.classList.add('active');}else{pane.classList.remove('active');}});});}const animatedSections=document.querySelectorAll('.why-choose-us-section,.warranty-section,.service-detail');if(animatedSections.length > 0){const observer=new IntersectionObserver((entries)=>{entries.forEach(entry=>{if(entry.isIntersecting){entry.target.classList.add('is-visible');observer.unobserve(entry.target);}});},{threshold: 0.1});animatedSections.forEach(section=>{observer.observe(section);});}});